create table dirkspzm32.s_erp_rcv_art_kd (
    sid                  varchar2(2 char) not null enable,
    firma_nr             number(3, 0) not null enable,
    artikel              varchar2(30 char) not null enable,
    kunden_nr            varchar2(10 char) not null enable,
    kd_art_nr            varchar2(30 char),
    kd_art_text1         varchar2(50 char),
    kd_art_text2         varchar2(50 char),
    lhm_name             varchar2(50 char),
    lhm_menge            number(12, 3),
    lhm_gewicht_kg       number(11, 5),
    lhm_ean              varchar2(15 char),
    lte_name             varchar2(22 char),
    lte_menge            number(12, 3),
    lte_gewicht_kg       number(12, 3),
    lte_breite_max       number(11, 2),
    lte_tiefe_max        number(11, 2),
    lte_hoehe_max        number(11, 2),
    lte_lhm_menge        number(12, 3),
    lte_lhm_pro_lage     number(2, 0),
    lte_lhm_lagen        number(2, 0),
    lte_hoehe_lage       number(3, 0),
    lte_ean              varchar2(15 char),
    pack_vorschr         varchar2(15 char),
    ean                  varchar2(15 char),
    aktiv                varchar2(1 char),
    b_datum              varchar2(19 char),
    created_date         date default sysdate not null enable,
    created_login_id     number(*, 0) default - 1 not null enable,
    last_change_date     date,
    last_change_login_id number(*, 0)
);

alter table dirkspzm32.s_erp_rcv_art_kd
    add constraint pk_erp_rcv_art_kd
        primary key ( sid,
                      firma_nr,
                      artikel,
                      kunden_nr )
            using index enable;


